from typing import Protocol
class EntityStore(Protocol):
    def get(self, id: str): ...
    def save(self, entity) -> None: ...
class MemStore:
    def __init__(self):
        self._d = {}
    def get(self, id: str):
        return self._d.get(id)
    def save(self, entity) -> None:
        self._d[entity["id"]] = entity
s = MemStore()
s.save({"id": "C1"})
print(s.get("C1"))

class FakeStore:
    def get(self, id):
        return {"id": id}
print(FakeStore().get("X"))

def load_entity(store, id):
    ent = store.get(id)
    if ent is None:
        raise KeyError(id)
    return ent
class S:
    def get(self, id):
        return None
try:
    load_entity(S(), "missing")
except KeyError as e:
    print("missing", e)

